            val v = prefs.getString(key, null)
            val payload = JSONObject().put("key", key)
            if (v == null) payload.put("value", JSONObject.NULL) else payload.put("value", v)
            success(id, payload)
        }

        @JavascriptInterface
        fun storageRemove(key: String?, callbackId: String?) {
            val id = requireCallbackId(callbackId)
            if (key.isNullOrBlank()) {
