        @JavascriptInterface
        fun pushLocalNotify(title: String?, body: String?, channelId: String?, callbackId: String?) {
            val id = requireCallbackId(callbackId)
            val t = title ?: "Notification"
            val b = body ?: ""
            val chId = channelId?.takeIf { it.isNotBlank() } ?: "hybrid_default"
            val chName = "Hybrid"

            activity.ensureNotificationChannel(chId, chName)

            val notif = NotificationCompat.Builder(activity, chId)
                .setSmallIcon(activity.applicationInfo.icon)
                .setContentTitle(t)
                .setContentText(b)
                .setAutoCancel(true)
                .setPriority(NotificationCompat.PRIORITY_DEFAULT)
                .build()

            val nm = NotificationManagerCompat.from(activity)
            val idInt = (System.currentTimeMillis() and 0x7FFFFFFF).toInt()
            try {
                nm.notify(idInt, notif)
                success(id, JSONObject().put("notified", true).put("notificationId", idInt))
            } catch (e: Throwable) {
                error(id, "NOTIFICATION_FAILED", e.message ?: "Failed to notify")
            }
        }

        @JavascriptInterface
        fun pushGetToken(callbackId: String?) {
            val id = requireCallbackId(callbackId)
            val token = prefs.getString("push_token", null)
            val payload = JSONObject()
            if (token == null) payload.put("token", JSONObject.NULL) else payload.put("token", token)
            success(id, payload)
        }

        @JavascriptInterface
        fun pushSetToken(token: String?, callbackId: String?) {
            val id = requireCallbackId(callbackId)
            if (token.isNullOrBlank()) {
                error(id, "INVALID_ARGUMENT", "token is required")
                return
            }
            prefs.edit().putString("push_token", token).apply()
            success(id, JSONObject().put("stored", true))
        }

        @JavascriptInterface
        fun openExternalUrl(url: String?, callbackId: String?) {
            val id = requireCallbackId(callbackId)
            if (url.isNullOrBlank()) {
                error(id, "INVALID_ARGUMENT", "url is required")
                return
            }
            try {
                val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                activity.startActivity(intent)
                success(id, JSONObject().put("opened", true))
            } catch (e: Throwable) {
                error(id, "OPEN_FAILED", e.message ?: "Failed to open")
            }
        }

        @JavascriptInterface
        fun base64ToStorage(key: String?, base64: String?, callbackId: String?) {
            val id = requireCallbackId(callbackId)
            if (key.isNullOrBlank() || base64.isNullOrBlank()) {
                error(id, "INVALID_ARGUMENT", "key and base64 are required")
                return
            }
            return try {
                val bytes = Base64.decode(base64, Base64.DEFAULT)
                val encoded = Base64.encodeToString(bytes, Base64.NO_WRAP)
                prefs.edit().putString(key, encoded).apply()
                success(id, JSONObject().put("stored", true).put("key", key))
            } catch (e: Throwable) {
                error(id, "DECODE_FAILED", e.message ?: "Failed to decode")
            }
        }
    }
